module multi_8bit(
    input [7:0] A,
    input [7:0] B,
    output reg [15:0] product
);
parameter [1:0] LOGIC_ZERO = 2'b00;
parameter [1:0] LOGIC_ONE = 2'b01;
reg [1:0] shift;
integer i;
always @(*) begin
    product = 16'b0;
    for (i = 0; i < 8; i = i + 1) begin
        if (B[i] == 1) begin
            product[i] = A + product[i];
            shift = LOGIC_ONE;
        end
        else begin
            shift = LOGIC_ZERO;
        end
        // Shift logic
        if (i < 7) begin
            A = A << 1;
        end
    end
end
endmodule
